  async watchObjectProperty<Record>(
    appId: string,
    objectKind: string,
    objectId: string,
    property: string,
    equals: unknown,
    defaults: RuntimeDefaults,
    options: WatchObjectPropertyOptions = {},
  ): Promise<WatchObjectPropertyResponse<Record>> {
    const request = {
      project_id: options.projectId ?? defaults.projectId,
      shard_id: options.shardId ?? defaults.shardId ?? "",
      app_id: options.appId ?? appId,
      object_kind: objectKind,
      object_id: objectId,
      property,
      equals_json: encodeJson(equals),
      timeout_ms: options.timeoutMs ?? 30_000,
      poll_interval_ms: options.pollIntervalMs ?? 5,
    };
    return await new Promise((resolve, reject) => {
      const client = this.readClient();
      const method = client.WatchObjectProperty;
      if (typeof method !== "function") {
        reject(new Error("Runtime gRPC method WatchObjectProperty is not available"));
        return;
      }
      const stream = method.call(client, request);
      let last: WatchObjectPropertyResponse<Record> | undefined;
      stream.on("data", (response: any) => {
        last = {
          status: response.status,
          matched: Boolean(response.matched),
          found: Boolean(response.found),
          record: response.found ? parseJson<Record>(response.record_json, null as Record) : undefined,
          elapsed_ms: response.elapsed_ms,
          attempts: Number(response.attempts ?? 0),
        };
        if (last.matched || last.status === "timeout" || last.status === "closed") {
          resolve(last);
        }
      });
      stream.on("error", reject);
      stream.on("end", () => resolve(last ?? {
        status: "closed",
        matched: false,
        found: false,
        elapsed_ms: 0,
        attempts: 0,
      }));
    });
  }

  async watchObjectProperties<Record>(
    predicates: WatchObjectPropertyPredicate[],
    defaults: RuntimeDefaults,
    options: WatchObjectPropertiesOptions = {},
  ): Promise<WatchObjectPropertiesResponse<Record>> {
    const request = {
      project_id: options.projectId ?? defaults.projectId,
      shard_id: options.shardId ?? defaults.shardId ?? "",
      predicates: predicates.map((predicate) => ({
        app_id: predicate.appId,
        object_kind: predicate.objectKind,
        object_id: predicate.objectId,
        property: predicate.property,
        equals_json: encodeJson(predicate.equals),
      })),
      match_mode: options.matchMode ?? "all",
      timeout_ms: options.timeoutMs ?? 30_000,
      poll_interval_ms: options.pollIntervalMs ?? 5,
    };
    const unaryMethod = this.client.WatchObjectPropertiesOnce;
    if (typeof unaryMethod === "function") {
      const client = this.readClient();
      const response = await promisifyUnary<any, any>(
        client,
        "WatchObjectPropertiesOnce",
        request,
        options.timeoutMs ?? this.deadlineMs,
      );
      return decodeWatchObjectPropertiesResponse<Record>(response);
    }
    return await new Promise((resolve, reject) => {
      const client = this.readClient();
      const method = client.WatchObjectProperties;
      if (typeof method !== "function") {
        reject(new Error("Runtime gRPC method WatchObjectProperties is not available"));
        return;
      }
      const stream = method.call(client, request);
      let last: WatchObjectPropertiesResponse<Record> | undefined;
      stream.on("data", (response: any) => {
        last = decodeWatchObjectPropertiesResponse<Record>(response);
        if (last.matched || last.status === "timeout" || last.status === "timed_out" || last.status === "closed") {
          resolve(last);
        }
      });
      stream.on("error", reject);
      stream.on("end", () => resolve(last ?? {
        status: "closed",
        matched: false,
        results: [],
        elapsed_ms: 0,
        attempts: 0,
        outbox_waits: 0,
      }));
    });
  }

