  async waitForWorkflow<Output = unknown, Input = unknown, Metadata = unknown>(
    appId: string,
    workflowId: string,
    workflowKey: string,
    defaults: RuntimeDefaults,
    options: WorkflowWaitOptions = {},
  ): Promise<WorkflowReadResponse<Output, Input, Metadata>> {
    const timeoutMs = options.timeoutMs ?? 30_000;
    if (options.drain ?? false) {
      const startedAt = Date.now();
      const pollIntervalMs = Math.max(1, options.pollIntervalMs ?? 5);
      while (Date.now() - startedAt <= timeoutMs) {
        await this.drainWorkflows(defaults, {
          projectId: options.projectId,
          shardId: options.shardId,
          maxCandidates: options.drainMaxCandidates,
          maxRecords: options.drainMaxRecords,
        });
        const read = await this.readWorkflow<Output, Input, Metadata>(
          appId,
          workflowId,
          workflowKey,
          defaults,
          options,
        );
        if (workflowTerminal(read.instance?.status)) return read;
        await sleepMs(pollIntervalMs);
      }
      return this.readWorkflow<Output, Input, Metadata>(
        appId,
        workflowId,
        workflowKey,
        defaults,
        options,
      );
    }
    const request = {
        project_id: options.projectId ?? defaults.projectId,
        shard_id: options.shardId ?? "",
        app_id: appId,
        workflow_id: workflowId,
        workflow_key: workflowKey,
        timeout_ms: timeoutMs,
      };
    const response = this.useReadStream
      ? await this.runtimeStreamRequest<any>(
          { watch_workflow: request },
          "watch_workflow",
          timeoutMs + 1000,
        )
      : await promisifyUnary<any, any>(
          this.readClient(),
          "WatchWorkflow",
          request,
          timeoutMs + 1000,
        );
    return this.decodeWorkflowReadResponse<Output, Input, Metadata>(response);
  }
